);

const FeedbackDisplay: React.FC<FeedbackDisplayProps> = ({ taskType, feedback, isLoading }) => {
  if (isLoading) {
    return <FeedbackSkeleton />;
  }

  if (!feedback) {
    return <FeedbackPlaceholder />;
