        **Output Requirements:**
        - **Mistakes:** List specific LR/GRA errors.
        - **Improvement:** Rewrite ALL awkward/unnatural sentences into clear academic English. UNDER NO CIRCUMSTANCES should the 'suggestedSentence' be in Vietnamese.
        `;

        const essayContent = `Please analyze the following essay.

        **Essay Prompt:** "${prompt}"
        **Word Count:** ${wordCount} words

        **Student's Essay:**
        ---
        ${essay}
        ---
        `;

        const parts = [];
        if (isTask1 && imageBase64) {
            parts.push({
                inlineData: { mimeType: 'image/jpeg', data: imageBase64 }
            });
        }
        parts.push({ text: essayContent });
        const contents = { parts };

        const baseFeedbackProperties = {
            strengths: { type: Type.STRING },
            weaknesses: { type: Type.STRING }
        };

        const mistakeSchema = {
            type: Type.OBJECT,
            properties: {
                originalPhrase: { type: Type.STRING },
                suggestedCorrection: { type: Type.STRING },
                explanation: { type: Type.STRING }
            },
            required: ['originalPhrase', 'suggestedCorrection', 'explanation']
        };

        const apiCall = async () => {
            const response = await ai.models.generateContent({
                model: feedbackModel,
                contents,
                config: {
                    systemInstruction,
                    responseMimeType: "application/json",
                    responseSchema: {
                        type: Type.OBJECT,
                        properties: {
                            taskCompletion: { 
                                type: Type.OBJECT,
                                properties: {
                                    strengths: { type: Type.STRING },
                                    weaknesses: { type: Type.STRING }
                                },
                                required: ['strengths', 'weaknesses']
                            },
                            taskCompletionScore: { type: Type.INTEGER },
                            coherenceCohesion: {
                                type: Type.OBJECT,
                                properties: {
                                    ...baseFeedbackProperties,
                                    referencingAndSubstitution: { type: Type.STRING, description: "Feedback on referencing, substitution, and REPETITION check (>4 times) in VIETNAMESE." }
                                },
                                required: ['strengths', 'weaknesses', 'referencingAndSubstitution']
                            },
                            coherenceCohesionScore: { type: Type.INTEGER },
                            lexicalResource: {
                                type: Type.OBJECT,
                                properties: {
                                    ...baseFeedbackProperties,
                                    mistakes: {
                                        type: Type.ARRAY,
                                        items: mistakeSchema
                                    }
                                },
                                required: ['strengths', 'weaknesses', 'mistakes']
                            },
                            lexicalResourceScore: { type: Type.INTEGER },
                            grammaticalRange: {
                                type: Type.OBJECT,
                                properties: {
                                    ...baseFeedbackProperties,
                                    mistakes: {
                                        type: Type.ARRAY,
                                        items: mistakeSchema
                                    }
                                },
                                required: ['strengths', 'weaknesses', 'mistakes']
                            },
                            grammaticalRangeScore: { type: Type.INTEGER },
                            sentenceImprovements: {
                                type: Type.ARRAY,
                                items: {
                                    type: Type.OBJECT,
                                        properties: {
                                        originalSentence: { type: Type.STRING },
                                        suggestedSentence: { type: Type.STRING, description: "The rewritten, more natural-sounding sentence in ACADEMIC ENGLISH. DO NOT use Vietnamese here." }
                                    },
                                    required: ['originalSentence', 'suggestedSentence']
                                }
                            }
                        },
                        required: ['taskCompletion', 'taskCompletionScore', 'coherenceCohesion', 'coherenceCohesionScore', 'lexicalResource', 'lexicalResourceScore', 'grammaticalRange', 'grammaticalRangeScore', 'sentenceImprovements']
                    },
                },
            });

            const jsonText = response.text;
            return JSON.parse(jsonText);
        };

        return await callWithRetry(apiCall);

    } catch (error) {
        handleApiError(error, 'get feedback from the AI');
    }
};

