                            },
                            coherenceCohesionScore: { type: Type.NUMBER },
                            lexicalResource: {
                                type: Type.OBJECT,
                                properties: { 
                                    strengths: { type: Type.STRING }, 
                                    weaknesses: { type: Type.STRING },
                                    mistakes: { type: Type.ARRAY, items: mistakeSchema }
